export function ClientTestimonialsSlider() {
  const [current, setCurrent] = useState(0)
  const [animating, setAnimating] = useState(false)
  const [direction, setDirection] = useState<"left" | "right">("right")

  const total = clientTestimonials.length

  const goTo = useCallback(
    (index: number, dir: "left" | "right") => {
      if (animating) return
      setDirection(dir)
      setAnimating(true)
      setTimeout(() => {
        setCurrent(index)
        setAnimating(false)
      }, 350)
    },
    [animating]
  )

  const prev = () => {
    const idx = (current - 1 + total) % total
    goTo(idx, "left")
  }

  const next = () => {
    const idx = (current + 1) % total
    goTo(idx, "right")
  }

  // Auto-advance
  useEffect(() => {
    const timer = setInterval(() => {
      const idx = (current + 1) % total
      goTo(idx, "right")
    }, 6000)
    return () => clearInterval(timer)
  }, [current, total, goTo])

  const t = clientTestimonials[current]

  const slideClass = animating
    ? direction === "right"
      ? "opacity-0 translate-x-8"
      : "opacity-0 -translate-x-8"
    : "opacity-100 translate-x-0"

  return (
    <div className="relative w-full max-w-4xl mx-auto select-none">
      {/* Card */}
      <div
        className={`transition-all duration-350 ease-in-out ${slideClass} bg-[#1F2937] border border-[#374151] rounded-sm p-8 md:p-12`}
        style={{ transition: "opacity 350ms ease, transform 350ms ease" }}
      >
        {/* Quote mark */}
        <div className="text-[#B68817] text-6xl font-serif leading-none mb-4 opacity-60">&ldquo;</div>

        {/* Quote text */}
        <p className="text-[#D1D5DB] text-lg md:text-xl leading-relaxed mb-8 italic">
          {t.quote}
        </p>

        {/* Founder info */}
        <div className="flex items-center gap-5 border-t border-[#374151] pt-6">
          {/* Photo circle */}
          <div className="flex-shrink-0 w-16 h-16 rounded-full overflow-hidden border-2 border-[#B68817] bg-[#374151] flex items-center justify-center">
            {t.photo ? (
              <img
                src={t.photo}
                alt={t.name}
                className="w-full h-full object-cover object-top"
              />
            ) : (
              <span className="text-[#B68817] text-xl font-bold">{t.initials}</span>
            )}
          </div>

          {/* Name & details */}
          <div>
            <p className="text-[#FAFAF8] font-bold text-lg">{t.name}</p>
            <p className="text-[#B68817] text-sm font-medium">{t.title}, {t.company}</p>
            <p className="text-[#6B7280] text-sm">{t.location}</p>
          </div>

          {/* Dot indicators */}
          <div className="ml-auto flex gap-2">
            {clientTestimonials.map((_, i) => (
              <button
                key={i}
                onClick={() => goTo(i, i > current ? "right" : "left")}
                className={`w-2 h-2 rounded-full transition-all duration-300 ${
                  i === current ? "bg-[#B68817] w-5" : "bg-[#374151] hover:bg-[#6B7280]"
                }`}
                aria-label={`Go to testimonial ${i + 1}`}
              />
            ))}
          </div>
        </div>
      </div>

      {/* Prev / Next arrows */}
      <button
        onClick={prev}
        className="absolute left-0 top-1/2 -translate-y-1/2 -translate-x-5 w-10 h-10 rounded-full bg-[#0F1419] border border-[#374151] text-[#B68817] flex items-center justify-center hover:border-[#B68817] transition-colors z-10"
        aria-label="Previous"
      >
        &#8592;
      </button>
      <button
        onClick={next}
        className="absolute right-0 top-1/2 -translate-y-1/2 translate-x-5 w-10 h-10 rounded-full bg-[#0F1419] border border-[#374151] text-[#B68817] flex items-center justify-center hover:border-[#B68817] transition-colors z-10"
        aria-label="Next"
      >
        &#8594;
      </button>
    </div>
  )
}
